  "CA-07": { id: "CA-07", name: "California Alternative Rates for Energy (CARE)", description: "30-35% discount on electric bill and 20% discount on gas bill for qualifying households.", category: "utility", icon: "spark", link: "https://www.cpuc.ca.gov/industries-and-topics/electrical-energy/electric-costs/care-fera-program" },
