  "CA-10": { id: "CA-10", name: "Energy Savings Assistance Program (ESA)", description: "Energy-saving home improvements (i.e. appliances, lighting, insulation).", category: "utility", icon: "spark", link: "https://www.cpuc.ca.gov/consumer-support/financial-assistance-savings-and-discounts/energy-savings-assistance" },
  "CA-11": { id: "CA-11", name: "Community-Based Adult Services (CBAS) / Adult Day Health Center (ADHC)", description: "Day program for seniors and adults with chronic medical, cognitive, or behavioral health conditions or disabilities, who meet all of the following criteria:\nAge 18 and older\nHave a chronic medical, cognitive, or behavioral health condition or disability that makes them at risk of needing institutional care\nEnrolled in Medi-Cal", category: "caretaker", icon: "heart", link: "https://aging.ca.gov/Programs_and_Services/Community-Based_Adult_Services/" },
  "CA-12": { id: "CA-12", name: "California Advanced Services Fund - Line Extension Program (LEP)", description: "Line extension infrastructure for phone and/or internet service to connect a property to existing or proposed facilities-based telecommunications infrastructure. The customer or a representative (i.e., the internet or phone provider) may apply on behalf of a customer or a group of eligible customers.\nThe person residing at the location to be served must qualify for either California LifeLine or California Alternative Rates for Energy (CARE).", category: "utility", icon: "spark", link: "https://www.cpuc.ca.gov/industries-and-topics/internet-and-phone/california-advanced-services-fund/casf-line-extension-program" },
  "CA-13": { id: "CA-13", name: "Medical Baseline", description: "Charged the lowest residential rate for gas and electricity bills, may be eligible for up to 20% off electric charges, and receive advanced notice of power outages, for people who are dependent on gas and electricity for medical reasons.\n\nQualifying medical conditions:\nCompromised immune system or life-threatening illness\nHemiplegia\nMultiple Sclerosis\nParaplegia\nQuadriplegia\nScleroderma\n\nOr qualifying medical equipment (home-use):\nAir mattress/ hospital beds\nApnea monitors\nBreather machines (IPPB)\nCompressors/ concentrators\nContinuous Positive Airway Pressure (CPAP)\nDialysis machines\nElectrostatic Nebulizers\nElectric Nerve Stimulators\nHemodialysis machines\nInfusion pumps\nInhalation pulmonary pressure\nIron lungs\nLeft Ventricular Assist Devices (LVAD)\nLympha Press Devices\nMotorized wheelchairs\nOxygen generators\nPacemaker monitor/ defibrillator\nPressure pads\nPressure pumps\nPulse oximeters/ monitors (must be used with other medical devices; cannot be battery powered)\nRespirators (all types)\nSuction machines", category: "utility", icon: "spark", link: "https://www.cpuc.ca.gov/consumer-support/financial-assistance-savings-and-discounts/medical-baseline" },
  "CA-14": { id: "CA-14", name: "Weatherization Assistance Program (WAP)", description: "Energy-saving home improvements (i.e., weatherization to improve energy efficiency and reduce energy bill.", category: "utility", icon: "spark", link: "https://www.csd.ca.gov/Pages/Residential-Energy-Efficiency.aspx" },
  "CA-15": { id: "CA-15", name: "California Children's Health Insurance Program (C-CHIP)", description: "Healthcare for children up to age 18.", category: "healthcare", icon: "heart", link: "https://www.healthforcalifornia.com/covered-california/income-limits" },
  "CA-16": { id: "CA-16", name: "Medi-Cal (Medicaid) for Pregnant Individuals", description: "Healthcare for people who are pregnant.", category: "healthcare", icon: "heart", link: "https://www.healthforcalifornia.com/covered-california/income-limits" },
  "CA-17": { id: "CA-17", name: "Medi-Cal (Medicaid) Access Program for Pregnant Individuals", description: "Reduced cost healthcare for people who are pregnant.", category: "healthcare", icon: "heart", link: "https://www.healthforcalifornia.com/covered-california/income-limits" },
