  "CA-25": { id: "CA-25", name: "Program of All-Inclusive Care for Elderly (PACE)", description: "Coordinated care for people who meet all of the following criteria:\nAge 55 and older\nCan live in the community without jeopardizing personal health or safety\nMeets requirement for needing skilled nursing care", category: "caretaker", icon: "heart", link: "https://www.dhcs.ca.gov/services/ltc/Pages/programofall-inclusivecarefortheelderly.aspx" },
  "CA-26": { id: "CA-26", name: "California Low Cost Automobile (CLCA) Insurance", description: "Low-cost automobile insurance for people who meet all of the following criteria:\nAge 16 and older\nHave a valid California driver's license\nOwn a vehicle valued at $25,000 or less\nHave a good driving record (no more than one at-fault property damage-only accident or no more than one point for a moving violation within the last 3 years, no at-fault accidents involving bodily injury or death within the last 3 years, and no felony or misdemeanor convictions for violations of the Vehicle Code).", category: "transportation", icon: "spark", link: "https://www.mylowcostauto.com/" },
  "CA-27": { id: "CA-27", name: "Property Tax Postponement", description: "Deferment of current-year property taxes on principal residence for people who meet all of the following criteria:\nAge 62 or older, blind or disabled,\nHousehold income of $55,181 or less,\nOwns and occupies the property as the principal place of residence,\nHas at least 40 percent equity in the property, and\nHas not had a reverse mortgage on the property.", category: "housing", icon: "home", link: "https://www.sco.ca.gov/ardtax_prop_tax_postponement.html" },
