  "CA-29": { id: "CA-29", name: "California State Board of Equalization - Disabled Veterans Exemption", description: "Disabled veterans may receive up to $150,000 off the full value of the property to reduce property tax liability for the principal place of residence.", category: "taxes", icon: "file", link: "https://boe.ca.gov/proptaxes/homeexem.htm" },
