  "CA-37.R1": { id: "CA-37.R1", name: "California Work Opportunity and Responsibility to Kids (CalWORKs)/ California's Temporary Assistance for Needy Families (TANF)", description: "Temporary cash aid for eligible families with at least one child, and for eligible students who meet any of the following requirements:\nFamilies where either parent is absent, disabled, or deceased\nFamilies where the primary income-earner is unemployed\nFamilies with relatives who are the caretaker for foster child(ren)\nNote:  complicated income equation", category: "income", icon: "dollar", link: "https://www.calworks.org/eligibility-process" },
  "CA-38": { id: "CA-38", name: "Low-Income Home Energy Assistance Program (LIHEAP)", description: "Multi-part program:\none-time financial assistance to help pay balance of utility bill; \nassistance for crisis (i.e. 24-48 hour disconnection notice); \nfree energy efficiency upgrades; AND\neducation energy efficiency practices and energy budget counseling.", category: "utility", icon: "spark", link: "https://www.csd.ca.gov/Pages/FindServicesInYourArea.aspx" },
