  "CA-42": { id: "CA-42", name: "Federal Special Veterans Benefit (SVB) and California Veterans Cash Benefit (CVCB)", description: "Cash assistance for veterans who meet all of the following criteria:\neligible for California's State Supplementary Payment in December 1999\nmember of the Philippines military force in the service of the United States during World War II\nreside in the Republic of the Philippines", category: "income", icon: "dollar", link: "https://www.cdss.ca.gov/veterans-cash-benefit" },
