  "CA37-01": { id: "CA37-01", name: "San Diego County General Relief", description: "Temporary cash assistance for people who meet the following criteria:\nSan Diego resident for at least 15 days with the intent to reside in San Diego County\nAge between 18 and 64, with rare exceptions\nMonthly income less than $598 (individual) or $819 (married)\nNo real property\nLess than $50 in liquid assets\nLess than $1,500 in total assets, excluding one vehicle valued at no more than $4,650", category: "income", icon: "dollar", link: "https://www.sandiegocounty.gov/content/sdc/hhsa/programs/ssp/general_relief.html" },
  "CA37-02": { id: "CA37-02", name: "San Diego County Medical Services (CMS)", description: "Healthcare of last resort for people who meet all of the following criteria:\nImmediate or long-term medical need\nAge between 21 and 64 years\nResident of San Diego County\nSign a lien form for services covered by CMS\nMeet CMS financial requirements or receive San Diego County General Relief", category: "healthcare", icon: "heart", link: "https://www.sandiegocounty.gov/content/sdc/hhsa/programs/ssp/county_medical_services/faq.html" },
