  "CA37-07": { id: "CA37-07", name: "Office of Military & Veterans Affairs - San Diego County", description: "Assistance for military veterans and their dependents to receive benefits counseling, prepare and submit claims, and appeal as needed.", category: "income", icon: "dollar", link: "https://www.sandiegocounty.gov/content/sdc/hhsa/programs/ssp/veterans_services.html" },
  "CA37-08": { id: "CA37-08", name: "Solid Waste Management Fee Financial Assistance Program", description: "Reduced out-of-pocket costs (50%) for trash and recycling fees for eligible homeowners who own and live in their own home as their primary residence, and receives San Diego City trash and recycling services.  Participation is limited and available on a first come, first serve basis.", category: "utility", icon: "spark", link: "https://www.sandiego.gov/environmental-services/trash-service-updates/financial-assistance" },
  "CA37-09": { id: "CA37-09", name: "San Diego Public Library's Discover & Go", description: "No-cost admission fee to participating museums, Aztec games, the San Diego Zoo and Safari Park, and other locations for individual and their families with a valid San Diego Public Library Card.  Supplies are limited.", category: "entertainment", icon: "spark", link: "https://www.sdcl.org/discoverandgo/" },
  "CA37-10": { id: "CA37-10", name: "Thomas Jefferson School of Law - Veterans' Legal Assistance Clinic", description: "No-cost legal assistance for veterans with a variety of legal needs including family law, government benefits, and estate planning.", category: "legal", icon: "file", link: "https://www.tjsl.edu/academics/clinics-internships/veterans-legal-assistance-clinic/" },
