  "CA37-15": { id: "CA37-15", name: "Cal Western School of Law - New Media Rights", description: "Assistance for entrepreneurs, journalists, and innovators whose projects require internet, intellectual property, privacy, and media law assistance.", category: "legal", icon: "file", link: "https://www.cwsl.edu/experiential_learning/clinics/new_media_rights.html" },
  "CA37-16": { id: "CA37-16", name: "Cal Western School of Law - Trademark Clinic", description: "Assistance for individuals and small businesses seeking a trademark from the United States Patent and Trademark Office.", category: "legal", icon: "file", link: "https://www.cwsl.edu/experiential_learning/clinics/trademark_clinic.html" },
  "CA37-17": { id: "CA37-17", name: "San Diego County Bar Association - Lawyer Referral Automated Service, Modest Means Program", description: "Modest Means or Flat fee program:  call (800) 464-1529", category: "legal", icon: "file", link: "https://www.sdcba.org/?pg=clientReferrals" },
  "CA37-18": { id: "CA37-18", name: "San Diego Volunteer Lawyers of San Diego", description: "Assistance with family law and domestic violence, microbusiness and nonprofit support, guardianship, restraining orders, landlord/tenant, education rights, HIV/AID legal services, Vision for Justice Collaborative, Special Immigrant Juvenile Status, Record Relief for Survivors.", category: "legal", icon: "file", link: "https://sdvlp.org/" },
  "CA37-19": { id: "CA37-19", name: "Legal Aid of San Diego", description: "Assistance with civil appeals, conservatorship, consumer protection and bankruptcy, education rights, eviction defense, family law, health coverage and access to care, housing discrimination, immigration, landlord-tenant issues, foreclosure, public housing, name or gender marker changes, outpatient behavioral health grievances and appeals, public assistance, restraining orders, SSI benefits, taxpayer rights and education.", category: "legal", icon: "file", link: "https://www.lassd.org/" },
  "CA37-20": { id: "CA37-20", name: "Cash Assistance Program for Immigrants (CAPI)", description: "Income for people who are age 65 and older, blind, or disabled and meet the following criteria:\nare not eligible for SSI and SSP due solely to immigration status\ncertain immigrants who entered the U.S. before August 22, 1996\nsponsored immigrants who entered the U.S. after August 21, 1996, and the sponsor is not deceased, disabled, or abusive\ncertain immigrants who entered the U.S. after August 21, 1996, and do not have a sponsor or have a sponsor who is deceased, disabled, or abusive.", category: "income", icon: "dollar", link: "https://www.sandiegocounty.gov/content/sdc/hhsa/programs/ssp/capi.html" },
  "CA37-21": { id: "CA37-21", name: "In-Home Supportive Service (IHSS)", description: "In-home assistance for people who meet all of the following criteria:\nCalifornia resident\nQualified for full-scope Medi-Cal (Medicaid)\nAge 65 or older, blind, or disabled\nUnable to live at home safely without help", category: "caretaker", icon: "heart", link: "https://www.sandiegocounty.gov/content/sdc/hhsa/programs/ais/Services/In-Home-Supportive-Services.html" },
  "CA37-22": { id: "CA37-22", name: "Section 8 Housing Choice Voucher", description: "Rental assistance.", category: "housing", icon: "home", link: "https://www.sandiegocounty.gov/content/sdc/sdhcd/rental-assistance/section-8-hcv-overview.html" },
  "CA37-23": { id: "CA37-23", name: "Public Housing", description: "Public housing for eligible families, senior citizens, and disabled persons who reside in the unincorporated areas of San Diego County, or the cities of Chula Vista, Coronado, Del Mar, El Cajon, Escondido, Imperial Beach, La Mesa, Lemon Grove, Poway, San Marcos, Santee, Solano Beach, or Vista.", category: "housing", icon: "home", link: "https://www.sandiegocounty.gov/content/sdc/sdhcd/rental-assistance/public-housing.html" },
  "CA37-24": { id: "CA37-24", name: "CA State Library Parks Pass and CA State Parks Pass Backpack", description: "No-cost vehicle pass to over 200 participating California state parks, permitting entry of one passenger vehicle with a capacity of 9 people or fewer, or one motorcycle.  Daytripper and trailblazer backpacks are equipped with binoculars, a compass, field guides, and other outdoor gear.  California state park passes and backpacks are available for check-out at San Diego Public Library branches with a valid library card.  Supplies are limited.", category: "entertainment", icon: "spark", link: "https://www.sandiego.gov/public-library/check-out-nature" },
  "CA37-25": { id: "CA37-25", name: "CA State Library Parks Pass", description: "No-cost vehicle pass to over 200 participating California state parks, permitting entry of one passenger vehicle with a capacity of 9 people or fewer, or one motorcycle.  California state park passes and backpacks are available for check-out at San Diego County Library branches with a valid library card.  Supplies are limited.", category: "entertainment", icon: "spark", link: "https://www.sdcl.org/stateparks/" },
  "CA37-26": { id: "CA37-26", name: "San Diego County Library's Discover & Go", description: "No-cost admission fee to participating museums, Aztec games, the San Diego Zoo and Safari Park, and other locations for individual and their families with a valid San Diego County Library Card.  Supplies are limited.", category: "entertainment", icon: "spark", link: "https://www.sdcl.org/discoverandgo/" },
  "CA37-04": { id: "CA37-04", name: "Balboa Park - Resident Free Day", description: "No-cost admission to participating museums (some on a rotating basis) to residents of the City and County of San Diego, and to active military personnel and their dependents", category: "entertainment", icon: "spark", link: "https://balboapark.org/resident-free-days/" },
  "CA37-27": { id: "CA37-27", name: "University of San Diego School of Law - Appellate Clinic", description: "Assistance to clients who have a referral from the pro bono panel at the Ninth Circuit Court of Appeal", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/appellate.php" },
  "CA37-28": { id: "CA37-28", name: "University of San Diego School of Law - Civil Litigation Clinic", description: "Assistance regarding consumer issues, breach of contract, and other related civil disputes", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/civil.php" },
  "CA37-29": { id: "CA37-29", name: "University of San Diego School of Law - Education and Disability Clinic", description: "Assistance for education-related disputes, including Individualized Education Programs (IEPs)", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/education-and-disability.php" },
