  "CA37-32": { id: "CA37-32", name: "University of San Diego School of Law - Housing Rights Clinic", description: "Assistance with housing-related matters", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/housing-rights.php" },
