  "CA37-34": { id: "CA37-34", name: "University of San Diego School of Law - State Income Tax Clinic", description: "Assistance with California income tax disputes and appeals", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/state-income-tax.php" },
  "CA37-35": { id: "CA37-35", name: "University of San Diego School of Law - State Sales and Use Tax Clinic", description: "Assistance with California sales and use tax decisions", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/state-use-tax.php" },
  "CA37-36": { id: "CA37-36", name: "University of San Diego School of Law - Veterans Clinic", description: "Assistance to veterans regarding GI Bill funds and predatory lending, discharge upgrades, and VA Disability Claims appeals", category: "legal", icon: "file", link: "https://www.sandiego.edu/veterans-clinic/" },
  "CA37-37": { id: "CA37-37", name: "University of San Diego School of Law - Women's Legal Clinic", description: "Assistance for victims of human trafficking and domestic violence; and assistance with child custody, guardianship, and dissolution matters", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/womens-clinic.php" },
  "CA37-38": { id: "CA37-38", name: "University of San Diego School of Law - Workers' Rights Clinic", description: "Assistance with employee rights, discrimination, medical leave, workplace safety, unpaid wages, unemployment benefits, harassment, and wrongful termination", category: "legal", icon: "file", link: "https://www.sandiego.edu/law/clinics/clinical-education/workers-rights.php" },
  "CA37-39": { id: "CA37-39", name: "San Diego Food Bank - Food Locator Map", description: "Food distribution sites through the Food Bank's network of community partners.  Distribution locations, days, and hours may vary.", category: "food", icon: "leaf", link: "https://www.sandiegofoodbank.org/get-food/" },
  "CA37-40": { id: "CA37-40", name: "San Diego Food Bank - food 4 kids Backpack Program", description: "Food distribution for \"chronically hungry\" children at qualifying schools to have food over the weekend when school is not in session.", category: "food", icon: "leaf", link: "https://www.sandiegofoodbank.org/programs/food-4-kids-backpack-program/" },
  "CA37-41": { id: "CA37-41", name: "San Diego Food Bank - Military Initiative", description: "Food distribution for active duty personnel, veterans, and their families", category: "food", icon: "leaf", link: "https://www.sandiegofoodbank.org/supporting-san-diegos-military-families-combating-hunger-through-the-food-banks-military-initiative/" },
  "CA37-42": { id: "CA37-42", name: "San Diego Food Bank - College Hunger-Relief Program", description: "Food distribution at colleges and universities in San Diego County", category: "food", icon: "leaf", link: "https://www.sandiegofoodbank.org/programs/college-hunger-relief-program/" },
  "CA37-43": { id: "CA37-43", name: "USDA Senior Food Program", description: "Food distribution of eligible seniors", category: "food", icon: "leaf", link: "https://www.sandiegofoodbank.org/programs/senior-food-program/" },
  "CA37-44": { id: "CA37-44", name: "San Diego Food Bank - Diaper Bank Program", description: "Diaper distribution for families in need who are caring for infants and toddlers.  Distribution locations, days, and hours may vary.", category: "health necessities", icon: "heart", link: "https://www.sandiegofoodbank.org/wp-content/uploads/2026/02/Diaper-Bank-Distribution-Site-List-English-Updated-2026.pdf" },
  "CA37-45": { id: "CA37-45", name: "San Diego County - Free 4 Menstrual Equity (Free4ME)", description: "No-cost menstrual product dispensers in San Diego County facilities, including libraries, Family Resource Centers, and Community Centers", category: "health necessities", icon: "heart", link: "https://www.livewellsd.org/i-want-to/get-involved/sector-engagement/youth/free4me" },
  "CA37-46": { id: "CA37-46", name: "San Diego County - Home Repair Program", description: "Loans and grants to eligible homeowners for minor health and safety repairs.  Homeowner must have resided in the home for at least 12 months prior to the application approval, and must live in unincorporated areas of San Diego County, Coronado, Del Mar, Imperial Beach, Lemon Grove, Poway, or Solana Beach.", category: "housing", icon: "home", link: "https://www.sandiegocounty.gov/content/sdc/sdhcd/home-buyers-owners/loan-grant.html" },
  "CA37-47": { id: "CA37-47", name: "San Diego County Water Authority - Residential Rebates & Programs", description: "List of rebate programs to incentivize residential customers to conserve water.  The rebate programs include high-efficiency water fixtures and toilets, rain barrels, landscaping and irrigation systems", category: "utility", icon: "spark", link: "https://www.sdcwa.org/your-water/water-use-efficiency/residential-rebates-programs/" },
  "CA37-48": { id: "CA37-48", name: "San Diego Law Library - Clinics", description: "List of legal clinics and self-help centers for a variety of legal issues including bankruptcy, SSI benefits, restraining orders.", category: "legal", icon: "file", link: "https://sandiegolawlibrary.org/clinics/" },
  "CA37-49": { id: "CA37-49", name: "San Diego Law Library - Legal Databases", description: "No cost computer access to legal databases at the San Diego Law Library, and at the following partner libraries:  Chula Vista Civic Center Branch Library, El Cajon Branch of the San Diego County Library, Escondido Public Library", category: "legal", icon: "file", link: "https://sandiegolawlibrary.org/contact-us/" },
  "CA37-50": { id: "CA37-50", name: "San Diego Law Library - Self-Help Legal Resources", description: "No cost self-help legal resources on common legal issues", category: "legal", icon: "file", link: "https://sandiegolawlibrary.org/self-help-center/" },
  "CA37-51": { id: "CA37-51", name: "San Diego Superior Court - Self-Help Center", description: "No cost self-help legal resources on common legal issues", category: "legal", icon: "file", link: "https://www.sdcourt.ca.gov/sdcourt/generalinformation/selfhelp" },
  "CA37-52": { id: "CA37-52", name: "California Court - Self-Help Guide to the California Court", description: "Resources to help navigate your court case", category: "legal", icon: "file", link: "https://selfhelp.courts.ca.gov/" },
  "CA37-53": { id: "CA37-53", name: "California Courts of Appeal - Self-Help Guide", description: "No cost self-help legal resources on appealing a court case in the California Court of Appeal", category: "legal", icon: "file", link: "https://selfhelp.courts.ca.gov/appeals" },
